import{_ as a,c as l,o,ag as t}from"./chunks/framework.S-Qvb3wi.js";const x=JSON.parse('{"title":"x402 API","description":"","frontmatter":{"title":"x402 API","aside":false,"outline":false},"headers":[],"relativePath":"kr/x402.md","filePath":"kr/x402.md"}'),i={name:"kr/x402.md"};function r(n,e,s,d,p,c){return o(),l("div",null,e[0]||(e[0]=[t('<h1 id="x402-api" tabindex="-1">x402 API <a class="header-anchor" href="#x402-api" aria-label="Permalink to &quot;x402 API&quot;">​</a></h1><p><strong>DGrid x402 API</strong>는 DGrid가 제공하는 요청 단위 LLM 추론 결제 방식입니다. 개발자나 에이전트는 별도의 계정을 만들거나 충전 잔액을 준비할 필요 없이, <strong>x402 결제 프로토콜</strong>을 통해 API 요청 흐름 안에서 바로 추론 비용을 결제할 수 있습니다.</p><p>이 때문에 x402는 특히 다음과 같은 상황에 적합합니다:</p><ul><li><strong>에이전트 및 자동화 워크플로</strong>가 추론 호출과 결제를 즉시 함께 처리해야 하는 경우</li><li><strong>서버 측 도구와 스크립트</strong>가 계정 개설이나 선충전 과정을 피하고 싶은 경우</li><li><strong>온디맨드 통합</strong>에서 &quot;추론 요청, 결제 승인, 결과 수신&quot;의 가장 짧은 경로를 원하는 경우</li></ul><h2 id="왜-x402가-중요한가" tabindex="-1">왜 x402가 중요한가 <a class="header-anchor" href="#왜-x402가-중요한가" aria-label="Permalink to &quot;왜 x402가 중요한가&quot;">​</a></h2><p>전통적인 AI 과금 방식은 보통 다음을 요구합니다:</p><ul><li>공급자 계정 생성</li><li>선불 잔액 충전 또는 결제 수단 연결</li><li>API 키, 쿼터, 청구 대시보드 관리</li></ul><p>반면 DGrid의 x402 방식에서는 흐름이 훨씬 직접적입니다:</p><blockquote><p>추론 요청 → 결제 요구사항 수신 → 서명 승인 → 결제와 추론을 함께 다시 요청</p></blockquote><p>에이전트 시스템 입장에서는 이것이 큰 단순화입니다. 모델을 사용할지 결정하는 동일한 런타임이, 별도의 계정 관리 플로우로 이동하지 않고도 같은 과정에서 결제 승인과 정산까지 처리할 수 있기 때문입니다.</p><h2 id="주요-사용-사례-에이전트가-직접-추론-비용-지불" tabindex="-1">주요 사용 사례: 에이전트가 직접 추론 비용 지불 <a class="header-anchor" href="#주요-사용-사례-에이전트가-직접-추론-비용-지불" aria-label="Permalink to &quot;주요 사용 사례: 에이전트가 직접 추론 비용 지불&quot;">​</a></h2><p>x402는 특히 다음과 같은 흐름을 위해 설계되었습니다:</p><ol><li>에이전트가 모델을 선택</li><li>에이전트가 추론 API 호출</li><li>에이전트가 해당 추론 비용 결제</li><li>에이전트가 결과를 받아 다음 작업 수행</li></ol><p>이 방식은 다음에 특히 유용합니다:</p><ul><li>백엔드 워크플로 안에서 동작하는 AI 에이전트</li><li>결제 인식형 추론이 필요한 Web3 에이전트 및 프로토콜</li><li>추론을 직접 결제 가능한 리소스로 취급하고 싶은 다단계 자동화</li></ul><h2 id="동작-방식" tabindex="-1">동작 방식 <a class="header-anchor" href="#동작-방식" aria-label="Permalink to &quot;동작 방식&quot;">​</a></h2><p>DGrid의 x402는 <strong>2단계 요청 플로우</strong>를 사용합니다:</p><ol><li><strong>첫 번째 요청은 <code>x-payment</code> 없이 전송</strong> 서버가 <code>402 Payment Required</code> 와 서명 가능한 payment requirements 를 반환합니다.</li><li><strong>클라이언트가 서명 후 재요청</strong> 클라이언트가 <code>x-payment</code> 페이로드를 생성하고, 같은 추론 요청을 결제 헤더와 함께 다시 보냅니다.</li></ol><p>이 패턴은 결제 승인을 명시적으로 유지하면서도 전체 추론 호출을 자동화 친화적으로 유지합니다.</p><h2 id="지원-결제-자산" tabindex="-1">지원 결제 자산 <a class="header-anchor" href="#지원-결제-자산" aria-label="Permalink to &quot;지원 결제 자산&quot;">​</a></h2><p>현재 x402 엔드포인트는 다음을 사용합니다:</p><ul><li><strong>프로토콜</strong>: x402</li><li><strong>네트워크</strong>: <code>eip155:56</code> (BSC)</li><li><strong>결제 토큰</strong>: <code>USD1</code></li><li><strong>자산 컨트랙트</strong>: <code>0x8d0D000Ee44948FC98c9B98A4FA4921476f08B0d</code></li></ul><h2 id="api-레퍼런스" tabindex="-1">API 레퍼런스 <a class="header-anchor" href="#api-레퍼런스" aria-label="Permalink to &quot;API 레퍼런스&quot;">​</a></h2><p>엔드포인트 수준의 문서는 x402 API 아래의 별도 하위 페이지 <a href="/kr/x402-api-reference">API Reference</a>로 분리했습니다.</p><p>x402 고유한 부분은 <strong>결제 핸드셰이크 플로우</strong>입니다. 먼저 엔드포인트를 호출해 <code>402 Payment Required</code> 를 받고, 이후 서명된 <code>x-payment</code> 헤더와 함께 같은 추론 요청을 다시 전송합니다.</p><p>모델 호출 형식, payload 관례, 공급자 스타일 예시는 DGrid <strong>Model API</strong> 도 함께 참고할 수 있습니다:</p><ul><li><a href="/kr/Model-API-Chat#chat-completions">OpenAI 호환 Chat Completions</a></li><li><a href="/kr/Model-API-Chat#native-claude-format">Claude 호환 Messages API</a></li></ul><p>위 페이지들은 표준 OpenAI 스타일과 Claude 스타일 요청 형식을 다루고, x402 API Reference 는 결제 래퍼와 이 엔드포인트에서 공통으로 사용하는 추론 필드에 초점을 맞춥니다.</p><h2 id="운영-메모" tabindex="-1">운영 메모 <a class="header-anchor" href="#운영-메모" aria-label="Permalink to &quot;운영 메모&quot;">​</a></h2><p>정산이 성공하면 서비스는 백엔드의 <code>x402_payment_logs</code> 테이블에 결제 로그를 기록합니다.</p><h2 id="x402와-ai-gateway를-언제-사용할까" tabindex="-1">x402와 AI Gateway를 언제 사용할까 <a class="header-anchor" href="#x402와-ai-gateway를-언제-사용할까" aria-label="Permalink to &quot;x402와 AI Gateway를 언제 사용할까&quot;">​</a></h2><p>다음이 필요하면 <strong>AI Gateway</strong> 를 사용하세요:</p><ul><li>전통적인 API 키 기반 접근</li><li>통합 계정 기반 모델 라우팅</li><li>표준 과금 방식의 장기 제품 통합</li></ul><p>다음이 더 중요하면 <strong>x402</strong> 를 사용하세요:</p><ul><li>요청 단위 직접 결제</li><li>선충전 잔액이 필요 없는 접근 방식</li><li>에이전트가 한 플로우 안에서 추론과 결제를 함께 처리하는 방식</li></ul>',35)]))}const u=a(i,[["render",r]]);export{x as __pageData,u as default};
